// Returns true and fills outData/outLen if a matching (tempC, fanSpeed) raw code exists.
inline bool findKelonRaw(int tempC, int fanSpeed, const uint16_t** outData, uint16_t* outLen) {
  for (size_t i = 0; i < kelonRawTableSize; i++) {
    if (kelonRawTable[i].tempC == tempC && kelonRawTable[i].fanSpeed == fanSpeed) {
      *outData = kelonRawTable[i].data;
      *outLen = kelonRawTable[i].len;
      return true;
    }
  }
  return false;
}
